INSERT INTO recipes VALUES(2,'麻婆豆腐',1,'/api/uploads/c935a1d3729c4640a96a5e335f83d276.png','["嫩豆腐 1盒","猪肉末 100g","豆瓣酱 1勺","花椒粉 适量","蒜末 适量","葱花 适量","生抽 1勺"]','["豆腐切小块，入沸水焯烫2分钟捞出沥干","锅中热油，放入肉末炒至变色","加入豆瓣酱炒出红油，放入蒜末炒香","加入适量清水煮沸，放入豆腐块轻轻翻动","加入生抽调味，用水淀粉勾薄芡","出锅撒上花椒粉和葱花"]','中等','15分钟','豆腐要轻轻翻动，避免碎裂',0,'2026-05-26 15:31:06.448240','2026-05-26 16:51:11.472938','["/api/uploads/c935a1d3729c4640a96a5e335f83d276.png"]');
INSERT INTO recipes VALUES(3,'可乐鸡翅',1,'/api/uploads/ae1f84b24be74ea3af9d7bc1cd3e6a06.png','["鸡翅 8个","姜片 适量","蒜 适量","可乐 1罐","料酒 1-2勺","生抽 1勺","老抽 1勺","蚝油 1勺","盐 半勺","白芝麻 适量"]','["鸡翅洗净两面划花刀，姜切片、蒜切末备用","锅里放小半锅水，水开后放入鸡翅、姜片，倒1-2勺料酒，煮3-5分钟，捞出冲洗干净浮末","锅里放油，油热后下姜片、蒜翻炒炒香，下煮好的鸡翅翻炒2分钟","倒入一勺生抽、一勺老抽、一勺蚝油，开小火继续翻炒，避免鸡翅糊锅底","把可乐直接倒进锅里，大火煮开，加半勺盐，转小火煮10-15分钟","煮的过程中记得不停翻炒，最后开大火收汁，撒上白芝麻即可出锅"]','简单','25分钟','煮的过程中要不停翻炒防止糊底，收汁时转大火让汤汁浓稠',0,'2026-05-26 15:31:16.642027','2026-06-05 01:30:29','["/api/uploads/ae1f84b24be74ea3af9d7bc1cd3e6a06.png"]');
INSERT INTO recipes VALUES(4,'紫菜蛋花汤',2,'/api/uploads/ac64ba0fade24bed86f0f26a8695561e.png','["紫菜适量","鸡蛋1个","盐适量","香油少许","葱花适量"]','["鸡蛋打散备用","锅中加水煮沸","放入紫菜搅散","淋入蛋液，待蛋花飘起后关火","加盐调味，淋入香油，撒葱花"]','简单','5分钟','蛋液要沿着锅边慢慢倒入，蛋花更漂亮',0,'2026-05-26 15:31:16.654293','2026-05-26 16:50:25.637315','["/api/uploads/ac64ba0fade24bed86f0f26a8695561e.png"]');
INSERT INTO recipes VALUES(5,'香菇肉酱',1,'/api/uploads/07dc8adaebc542b28fa9cf86c41e9ffa.png','["猪肉馅300g（3肥7瘦）","香菇4-5朵","大葱半根","蒜4-5瓣","花椒粉1勺","料酒适量","生抽2勺","老抽1勺","蚝油1勺","白糖1勺","胡椒粉1勺","盐适量","黄豆酱1勺","甜面酱1勺","淀粉水适量"]','["猪肉馅、香菇切丁，大葱和蒜切末备用","锅中油热，下1勺花椒粉爆香，下肉馅炒至变色，淋一圈料酒去腥","中小火翻炒至肉末微焦，下葱蒜末，加2勺生抽、1勺蚝油翻炒均匀","加入香菇丁翻炒，再加1勺老抽提色，1勺白糖、1勺胡椒粉、适量盐翻炒均匀","加入黄豆酱和甜面酱各1勺，翻炒均匀后倒入1小碗清水","酱烧开后勾薄芡，撒上葱花即可出锅"]','简单','15分钟','肉馅要用3肥7瘦的，炒出来更香；黄豆酱和甜面酱的比例可根据口味调整',0,'2026-06-02 00:19:41.880689','2026-06-02 05:14:13.507734','["/api/uploads/07dc8adaebc542b28fa9cf86c41e9ffa.png","/api/uploads/0d0b18875a574a9c9c9073bd21e526ed.JPG"]');
INSERT INTO recipes VALUES(6,'杏鲍菇烤串',5,'/api/uploads/7422d4a423534464bac2572393ec7daa.png','["杏鲍菇 500g","生抽 15g","蚝油 15g","番茄酱 15g","孜然粒 3g","孜然粉 3g","辣椒粉 3g","花椒粉 1g","白芝麻 5g","花生油 20g"]','["杏鲍菇洗净切厚片（2-3毫米），水开后下锅烫两分钟","捞出过凉水，挤干多余水分。用竹签串好（竹签提前泡水）","将生抽、蚝油、番茄酱、孜然粒、孜然粉、辣椒粉、花椒粉、花生油混合调成酱料","杏鲍菇串刷上酱料","放入空气炸锅中180度烤6分钟，取出翻面","翻面后再刷一层酱料，继续烤6分钟","出炉撒上白芝麻即可"]','简单','12分钟','中途翻面时再刷一层酱料，味道更浓郁',0,'2026-06-05 00:59:00','2026-06-05 02:11:59.458444','["/api/uploads/7422d4a423534464bac2572393ec7daa.png"]');
INSERT INTO recipes VALUES(7,'万能蘸水',3,'/api/uploads/db109462dfc9473f8d1930c871d85ef3.png','["糊辣椒面","醋","香油","葱花","香菜","小米辣"]','["糊辣椒面打底，倒入醋和香油","加入葱花香菜、小米辣","淋两勺煮菜的原汤搅拌均匀即可"]','简单','5分钟','',0,'2026-06-05 01:33:47.808646','2026-06-05 02:11:37.205567','["/api/uploads/db109462dfc9473f8d1930c871d85ef3.png"]');
INSERT INTO recipes VALUES(8,'水煮菜',3,'/api/uploads/c05ccd5544594dcc86f1b86bea4d0834.JPG','[]','[]','简单','20分钟','',0,'2026-06-05 01:43:57.050286','2026-06-05 01:43:57.050294','["/api/uploads/c05ccd5544594dcc86f1b86bea4d0834.JPG","/api/uploads/1b345c49e5624e1db8065c82ef7a3561.JPG"]');
INSERT INTO recipes VALUES(9,'辣椒油',4,'/api/uploads/706ef2e0b0f94bd6b7d063cb29f1a8cc.JPG','["食用油 适量","粗辣椒粉 适量","细辣椒粉 适量","白芝麻 适量","花生碎 适量","香油 少许","盐 适量","糖 少许","干料：姜片、大蒜、八角、桂皮、香叶、白芷、小茴香、花椒","湿料：洋葱、香菜、大葱"]','["准备干料：姜片、大蒜、八角、桂皮、香叶、白芷、小茴香、花椒","准备湿料：洋葱、香菜、大葱","粗辣椒粉、细辣椒粉、盐、糖、白芝麻、花生碎","倒入一点香油","锅中倒入适量油，下入干料。大火烧热七八成热转成小火，炸七八分钟","下入湿料（用厨房纸巾吸干水分），炸七八分钟","捞出料渣子","加入一勺炸好的热油搅拌辣椒面（防止糊）","油温加到最热，边搅拌边倒热油","盖上盖子放置30分钟"]','简单','25分钟','',0,'2026-06-05 01:55:14.172062','2026-06-05 02:23:43.841567','["/api/uploads/706ef2e0b0f94bd6b7d063cb29f1a8cc.JPG"]');
INSERT INTO recipes VALUES(10,'山东炒鸡',1,'/api/uploads/72c2d97354ac419692a8a6f90e0b48f4.png','["半只新鲜公鸡","小米辣 适量","干辣椒 适量","青花椒 适量","白芷 1个","八角 1个","大蒜头 适量","姜片 适量","葱段 适量","螺旋椒 适量","生抽 2勺","老抽 2勺","料酒 2勺","蚝油 1勺","黄豆酱 1勺","甜面酱 1勺","白糖 少许"]','["半只鸡放入盆中，泡1-2小时，倒掉血水","鸡肉沥干水份，起锅烧油，油热下姜片炸至微黄","关小火放入小米辣、干辣椒、青花椒、白芷、八角、蒜头炒香（螺旋椒除外）","倒入鸡肉炒至微黄","倒入提前调好的料汁（生抽2勺、老抽2勺、料酒2勺、蚝油1勺、黄豆酱1勺、甜面酱1勺、少许白糖）","加入开水炖煮半小时","临出锅前倒入螺旋椒即可"]','中等','40分钟','鸡肉提前泡水去血水，螺旋椒临出锅前放保持口感',0,'2026-06-05 02:01:40','2026-06-05 02:10:25.208628','["/api/uploads/72c2d97354ac419692a8a6f90e0b48f4.png"]');
INSERT INTO recipes VALUES(11,'水饺',8,'/api/uploads/6c349abb76a44f4c9524303cc50d9174.png','["面粉 500g","猪肉馅 300g","白菜 半颗","葱姜水 适量","生抽 2勺","蚝油 1勺","盐 适量","香油 少许"]','["面粉加水揉成光滑面团，醒面30分钟","白菜切碎，撒盐腌出水分后挤干","猪肉馅加入葱姜水、生抽、蚝油、盐搅拌上劲","加入白菜碎和香油拌匀","面团搓条切剂子，擀成饺子皮","包入馅料捏紧","水烧开下饺子，点三次冷水，饺子浮起即熟"]','中等','40分钟','白菜要挤干水分，饺子皮擀薄一些口感更好',0,'2026-06-05 02:14:03','2026-06-05 02:14:03','["/api/uploads/6c349abb76a44f4c9524303cc50d9174.png"]');
INSERT INTO recipes VALUES(12,'馄饨',8,'/api/uploads/394cb8c12db0455fb4e1772ae8a0ba35.png','["馄饨皮 适量","猪肉馅 200g","葱花 适量","姜末 少许","生抽 1勺","蚝油 半勺","盐 适量","紫菜、虾皮、香菜 适量"]','["猪肉馅加入葱花、姜末、生抽、蚝油、盐搅拌均匀","取一张馄饨皮，放适量馅料","对角折成三角形，两角向中间捏紧","锅中水烧开，下馄饨煮至浮起","碗中放紫菜、虾皮、香菜、生抽、香油","盛入馄饨和汤即可"]','简单','20分钟','馄饨皮要买薄的，馅料不要放太多',0,'2026-06-05 02:14:03','2026-06-05 02:14:03','["/api/uploads/394cb8c12db0455fb4e1772ae8a0ba35.png"]');
INSERT INTO recipes VALUES(13,'小笼包',8,'/api/uploads/28521511f8664dcead0330c5bcab5bfc.png','["面粉 300g","猪肉馅 250g","皮冻 100g","生抽 2勺","蚝油 1勺","白糖 半勺","姜末 少许","盐 适量"]','["面粉加温水揉成面团，醒面30分钟","猪肉馅加入生抽、蚝油、白糖、姜末、盐搅拌上劲","皮冻切碎拌入馅料中","面团搓条切小剂子，擀成薄皮","包入馅料捏出褶子","蒸锅刷油，放入小笼包","大火蒸8-10分钟即可"]','较难','50分钟','皮冻是汤汁的关键，没有皮冻可以用猪皮冻代替',0,'2026-06-05 02:14:03','2026-06-05 02:14:03','["/api/uploads/28521511f8664dcead0330c5bcab5bfc.png"]');
INSERT INTO recipes VALUES(14,'烧麦',8,'/api/uploads/6b863f54c3f14c3ab8e88258c471ac90.png','["糯米 200g","猪肉馅 150g","香菇 5朵","胡萝卜 半根","生抽 2勺","蚝油 1勺","烧麦皮 适量","葱花 适量"]','["糯米提前泡4小时，蒸熟备用","香菇、胡萝卜切丁","锅中放油，炒香猪肉馅，加入香菇丁和胡萝卜丁","加入生抽、蚝油翻炒，倒入蒸好的糯米拌匀","取烧麦皮，包入馅料，顶部捏出花边","蒸锅水烧开，大火蒸10分钟"]','中等','60分钟','糯米要提前泡软蒸熟，馅料可以提前一晚准备',0,'2026-06-05 02:14:03','2026-06-05 02:14:03','["/api/uploads/6b863f54c3f14c3ab8e88258c471ac90.png"]');
INSERT INTO recipes VALUES(15,'韭菜盒子',8,'/api/uploads/8bd25f7b4db94e7dae5844dddbca7c42.png','["面粉 300g","韭菜 200g","鸡蛋 3个","虾皮 适量","盐 适量","香油 少许"]','["面粉加温水揉成面团，醒面20分钟","韭菜洗净切碎，鸡蛋炒散","韭菜、鸡蛋、虾皮混合，加盐和香油拌匀","面团擀成圆片，包入馅料对折捏紧边缘","平底锅刷油，放入韭菜盒子","中小火煎至两面金黄即可"]','简单','30分钟','韭菜要最后放盐，防止出水太多',0,'2026-06-05 02:14:03','2026-06-05 02:14:03','["/api/uploads/8bd25f7b4db94e7dae5844dddbca7c42.png"]');
INSERT INTO recipes VALUES(16,'红糖馒头',8,'/api/uploads/d682824fa72047608d03328e5256216a.png','["面粉 500g","红糖 80g","酵母 5g","温水 250ml"]','["红糖加温水搅拌至融化，放凉","面粉中加入酵母，倒入红糖水揉成面团","盖保鲜膜发酵至两倍大","面团排气揉匀，分成等份小剂子","揉成圆形，放入蒸笼二次醒发15分钟","冷水上锅，大火蒸15分钟，关火焖3分钟再开盖"]','简单','60分钟','红糖水一定要放凉再加酵母，否则会烫死酵母',0,'2026-06-05 02:14:03','2026-06-05 02:14:03','["/api/uploads/d682824fa72047608d03328e5256216a.png"]');
INSERT INTO recipes VALUES(17,'砂锅麻辣烫',8,'/api/uploads/5f98c5dcf1d04a1aab97dd01d0e1d6f4.png','[]','["二八酱加入温水搅拌均匀","准备食材：牛筋面、丸子、豆皮、海带、蘑菇、土豆、菠菜等","砂锅中加水，放入两片香叶、一小块白芷、一些冰糖、一小块火锅底料","加入一勺盐、一勺鸡精、一勺猪油","大火烧开转中小火10分钟","打出料渣子，放入食材煮熟","放一点生抽、一点醋（可不加）","放入蒜水、麻油、辣椒油、芝麻酱"]','简单','20分钟','',0,'2026-06-05 02:20:21.501708','2026-06-05 02:31:16.848602','["/api/uploads/5f98c5dcf1d04a1aab97dd01d0e1d6f4.png"]');
